import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface EnergyUsageData {
  currentConsumption: {
    value: number;
    unit: string;
  };
  dailyCost: {
    value: number;
    currency: string;
  };
  usageTrend: number[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const energyData = response.data as EnergyUsageData;
  const metaData = response.meta as MetaData;
  const clipPathId = React.useId();

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 350,
        maxWidth: 450,
        bgcolor: metaData.theme === 'dark' ? '#2E3B4E' : '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: metaData.primaryColor }}>
              Current Consumption
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFFFFF' }}>
              {energyData.currentConsumption.value} {energyData.currentConsumption.unit}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Daily Cost: {energyData.dailyCost.currency} {energyData.dailyCost.value.toFixed(2)}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: energyData.usageTrend,
                  color: metaData.accentColor,
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: energyData.usageTrend.map((_, index) => index),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'usage' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="usage"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
